div.p:
c
// Only pops if condition is falsy.
// If truthy, the loop continues with
// the condition still on the stack!
if (is_falsy(vm_peek(vm, 0))) {
vm_pop(vm); // Conditional Pop
vm->ip = target;
}

c
// Always pop to maintain neutrality.
// Every path through the instruction
// cleans its own arguments.
Value cond = vm_pop(vm);
if (is_falsy(cond)) {
vm->ip = target;
}
